import React, { useState, useEffect, useRef } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';

// 🔑 CORRECTION CRITIQUE : Worker avec fallback version fixe
const workerUrl = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjs.version || '3.11.174'}/pdf.worker.min.js`;
pdfjs.GlobalWorkerOptions.workerSrc = workerUrl;

interface PDFViewerProps {
  fileUrl: string;
  onDocumentLoad?: (numPages: number) => void;
}

const PDFViewer: React.FC<PDFViewerProps> = ({ fileUrl, onDocumentLoad }) => {
  const [numPages, setNumPages] = useState<number | null>(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [scale, setScale] = useState(1.0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const loadTimeout = useRef<NodeJS.Timeout | null>(null);
  const isMounted = useRef(true);

  // Nettoyage du timeout au démontage
  useEffect(() => {
    return () => {
      isMounted.current = false;
      if (loadTimeout.current) clearTimeout(loadTimeout.current);
    };
  }, []);

  // Réinitialisation à chaque changement de fichier
  useEffect(() => {
    if (loadTimeout.current) clearTimeout(loadTimeout.current);
    
    setLoading(true);
    setError(null);
    setPageNumber(1);
    
    // Timeout de sécurité (15 secondes max)
    loadTimeout.current = setTimeout(() => {
      if (isMounted.current && loading) {
        setError('⏳ Temps de chargement dépassé\n\n• Vérifiez votre connexion\n• Le PDF est-il trop volumineux ?\n• L\'URL est-elle valide ?');
        setLoading(false);
      }
    }, 15000);
    
    return () => {
      if (loadTimeout.current) clearTimeout(loadTimeout.current);
    };
  }, [fileUrl]);

  const onDocumentSuccess = (pdf: any) => {
    if (!isMounted.current) return;
    if (loadTimeout.current) clearTimeout(loadTimeout.current);
    
    setNumPages(pdf.numPages);
    setLoading(false);
    setError(null);
    
    // Ajuster le zoom selon le nombre de pages
    if (pdf.numPages > 10) setScale(0.9);
    
    if (onDocumentLoad) onDocumentLoad(pdf.numPages);
  };

  const onDocumentError = (err: any) => {
    if (!isMounted.current) return;
    if (loadTimeout.current) clearTimeout(loadTimeout.current);
    
    console.error('❌ Erreur PDF:', err);
    
    let message = '📄 Impossible de charger le PDF';
    
    if (err.name === 'InvalidPDFException') {
      message = '⚠️ Fichier PDF corrompu ou invalide';
    } else if (err.name === 'MissingPDFException') {
      message = '⚠️ PDF introuvable (404)\nVérifiez l\'URL du fichier';
    } else if (err.message?.includes('CORS') || err.message?.includes('cross-origin')) {
      message = '🔒 Erreur CORS\nLe bucket Supabase n\'est pas public';
    } else if (err.status === 403) {
      message = '🔐 Accès refusé\nLe fichier n\'est pas public dans Supabase';
    } else if (err.status === 404) {
      message = '🔍 PDF non trouvé\nURL incorrecte ou fichier supprimé';
    }
    
    setError(`${message}\n\nDétails techniques:\n${err.message || 'Erreur inconnue'}`);
    setLoading(false);
  };

  const goToPrevPage = () => {
    setPageNumber(prev => Math.max(prev - 1, 1));
  };

  const goToNextPage = () => {
    setPageNumber(prev => Math.min(prev + 1, numPages || 1));
  };

  const zoomIn = () => {
    setScale(prev => Math.min(prev + 0.2, 3.0));
  };

  const zoomOut = () => {
    setScale(prev => Math.max(prev - 0.2, 0.5));
  };

  // 🔑 DEBUG : Afficher l'URL dans la console
  useEffect(() => {
    console.log('🔍 URL PDF chargée:', fileUrl);
    console.log('👷 Worker PDF.js:', workerUrl);
  }, [fileUrl]);

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-800">
      {/* Barre d'outils */}
      <div className="flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-700/50">
        <div className="flex items-center gap-3">
          <button
            onClick={goToPrevPage}
            disabled={pageNumber <= 1 || loading}
            className={`p-1.5 rounded-md ${
              pageNumber <= 1 || loading
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
            title="Page précédente (Flèche gauche)"
          >
            <i className="fas fa-chevron-left"></i>
          </button>
          
          <div className="flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-gray-300">
            <span>Page</span>
            <input
              type="number"
              value={pageNumber}
              onChange={(e) => {
                const page = parseInt(e.target.value);
                if (!isNaN(page) && page >= 1 && page <= (numPages || 1)) {
                  setPageNumber(page);
                }
              }}
              min="1"
              max={numPages || 1}
              disabled={loading}
              className="w-12 text-center px-1.5 py-0.5 border border-gray-300 dark:border-gray-600 rounded text-gray-900 dark:text-white disabled:bg-gray-100 disabled:dark:bg-gray-700"
            />
            <span>sur {numPages || '?'}</span>
          </div>
          
          <button
            onClick={goToNextPage}
            disabled={pageNumber >= (numPages || 1) || loading}
            className={`p-1.5 rounded-md ${
              pageNumber >= (numPages || 1) || loading
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
            title="Page suivante (Flèche droite)"
          >
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
        
        <div className="flex items-center gap-2">
          <button
            onClick={zoomOut}
            disabled={loading}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md disabled:opacity-50"
            title="Zoom arrière"
          >
            <i className="fas fa-search-minus"></i>
          </button>
          
          <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
            {Math.round(scale * 100)}%
          </span>
          
          <button
            onClick={zoomIn}
            disabled={loading}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md disabled:opacity-50"
            title="Zoom avant"
          >
            <i className="fas fa-search-plus"></i>
          </button>
          
          <button
            onClick={() => setScale(1.0)}
            disabled={loading}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md disabled:opacity-50"
            title="Zoom 100%"
          >
            <i className="fas fa-expand"></i>
          </button>
        </div>
        
        <button
          onClick={() => window.open(fileUrl, '_blank')}
          className="px-3 py-1.5 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-md flex items-center gap-1.5 transition-colors"
          title="Ouvrir dans un nouvel onglet"
        >
          <i className="fas fa-external-link-alt"></i>
          <span className="hidden sm:inline">Ouvrir</span>
        </button>
      </div>
      
      {/* Zone de visualisation */}
      <div className="flex-1 overflow-auto bg-white dark:bg-gray-800 flex items-center justify-center p-4 relative">
        {loading && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 dark:bg-gray-800/80 z-10">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
            <p className="text-gray-600 dark:text-gray-400 font-medium">Chargement du PDF...</p>
            <p className="text-xs text-gray-500 dark:text-gray-500 mt-1">Cela peut prendre quelques secondes</p>
          </div>
        )}
        
        {error && (
          <div className="absolute inset-0 flex items-center justify-center p-6 z-10">
            <div className="max-w-md w-full bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-5 text-center">
              <i className="fas fa-exclamation-triangle text-red-500 text-4xl mb-3"></i>
              <h3 className="font-bold text-red-800 dark:text-red-200 mb-2">Erreur de chargement</h3>
              <p className="text-red-700 dark:text-red-300 text-sm whitespace-pre-line mb-4">{error}</p>
              
              <div className="space-y-2">
                <button
                  onClick={() => window.open(fileUrl, '_blank')}
                  className="w-full px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-md text-sm flex items-center justify-center gap-2"
                >
                  <i className="fas fa-file-pdf"></i>
                  Ouvrir le PDF directement
                </button>
                
                <button
                  onClick={() => {
                    setLoading(true);
                    setError(null);
                  }}
                  className="w-full px-4 py-2 bg-gray-200 hover:bg-gray-300 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 rounded-md text-sm"
                >
                  <i className="fas fa-redo mr-2"></i>
                  Réessayer
                </button>
              </div>
              
              <div className="mt-4 pt-4 border-t border-red-200 dark:border-red-800 text-left text-xs text-red-700 dark:text-red-400">
                <p className="font-medium mb-1">Pour résoudre ce problème :</p>
                <ul className="list-disc list-inside space-y-1">
                  <li>Vérifiez que le bucket Supabase est <span className="font-bold">public</span></li>
                  <li>Testez l'URL du PDF dans un nouvel onglet</li>
                  <li>Assurez-vous que le fichier n'est pas corrompu</li>
                </ul>
              </div>
            </div>
          </div>
        )}
        
        <Document
          file={fileUrl}
          onLoadSuccess={onDocumentSuccess}
          onLoadError={onDocumentError}
          loading=""
          error=""
          className="max-w-full"
        >
          <Page
            pageNumber={pageNumber}
            scale={scale}
            renderTextLayer={true}
            renderAnnotationLayer={true}
            className="shadow-lg rounded-lg"
          />
        </Document>
      </div>
      
      {/* Indicateur en bas */}
      <div className="py-2 px-4 text-center text-xs text-gray-500 dark:text-gray-400 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-700/50">
        {loading ? 'Préparation du document...' : 
         error ? 'Erreur détectée' : 
         `PDF chargé • ${numPages} page${numPages && numPages > 1 ? 's' : ''}`}
      </div>
    </div>
  );
};

export default PDFViewer;
